console.log('const ilə dəyişən nümunəsi...');
const personName = 'Ayxan';
console.log('Ad:', personName);
// personName = 'Elvin'; // Səhv: Assignment to constant variable
// Output:
// const ilə dəyişən nümunəsi...
// Ad: Ayxan

console.log('Yenidən təyin qadağası...');
const count = 10;
// count = 20; // Səhv: Assignment to constant variable
console.log('Dəyər:', count);
// const count = 30; // Səhv: Identifier 'count' has already been declared
// Output:
// Yenidən təyin qadağası...
// Dəyər: 10

console.log('Blok scope nümunəsi...');
if (true) {
    const message = 'Blok daxilində';
    console.log(message);
}
// console.log(message); // Səhv: message is not defined
// Output:
// Blok scope nümunəsi...
// Blok daxilində

console.log('Hoisting nümunəsi...');
// console.log(value); // Səhv: Cannot access 'value' before initialization
const value = 100;
console.log('Təyin olunduqdan sonra:', value);
// Output:
// Hoisting nümunəsi...
// Təyin olunduqdan sonra: 100

console.log('Obyekt ilə const nümunəsi...');
const person = { name: 'Ayxan' };
person.name = 'Elvin'; // İşləyir
console.log('Dəyişdirilmiş obyekt:', person);
// person = { name: 'Rəşad' }; // Səhv: Assignment to constant variable
// Output:
// Obyekt ilə const nümunəsi...
// Dəyişdirilmiş obyekt: { name: 'Elvin' }

console.log('const vs let vs var nümunəsi...');
if (true) {
    var varValue = 'Var dəyəri';
    let letValue = 'Let dəyəri';
    const constValue = 'Const dəyəri';
}
console.log(varValue); // İşləyir
// console.log(letValue); // Səhv: letValue is not defined
// console.log(constValue); // Səhv: constValue is not defined
// Output:
// const vs let vs var nümunəsi...
// Var dəyəri

console.log('Səhvə yol açan nümunə...');
// const number; // Səhv: Missing initializer in const declaration
const number = 5;
// number = 10; // Səhv: Assignment to constant variable
console.log('Dəyər:', number);
// Output:
// Səhvə yol açan nümunə...
// Dəyər: 5

